module synchronizer
(
    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output [3:0] dataout
);
// ------------------------------
//        Your Code
// ------------------------------
reg [3:0] data_reg;
reg [3:0] en_data_reg;
reg [3:0] en_clap_one;
reg [3:0] en_clap_two;
reg [3:0] dataout_reg;
assign dataout = dataout_reg;
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) data_reg <= 4'b0000;
    else data_reg <= data_in;
end
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) en_data_reg <= 1'b0;
    else en_data_reg <= data_en;
end
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) en_clap_one <= 1'b0;
    else en_clap_one <= en_data_reg;
end
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) en_clap_two <= 1'b0;
    else en_clap_two <= en_clap_one;
end
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) dataout_reg <= 4'b0000;
    else if (en_clap_two) dataout_reg <= data_reg;
    else dataout_reg <= dataout_reg;
end
endmodule
